import{e as t}from"./app.3d435d82.js";import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";const a={},n=t('<h2 id="\u524D\u8A00" tabindex="-1"><a class="header-anchor" href="#\u524D\u8A00" aria-hidden="true">#</a> \u524D\u8A00</h2><p>\u65E2\u7136\u8981\u5B66\u4E60\u4E00\u95E8\u6280\u672F\uFF0C\u90A3\u4E48\u5C31\u5148\u6765\u4E86\u89E3\u4E0B\u5B83\u7684\u5386\u53F2\uFF0C\u6211\u4EEC\u4E3A\u4EC0\u4E48\u8981\u4F7F\u7528\u5B83\uFF0C\u4EE5\u53CA\u6211\u4EEC\u80FD\u7528\u5B83\u6765\u5E72\u5565\u3002</p><h2 id="\u5386\u53F2\u80CC\u666F" tabindex="-1"><a class="header-anchor" href="#\u5386\u53F2\u80CC\u666F" aria-hidden="true">#</a> \u5386\u53F2\u80CC\u666F</h2><p>1990 \u5E74\u4EE3\u521D\uFF0CSun \u516C\u53F8\u7684\u8A79\u59C6\u65AF\xB7\u9AD8\u65AF\u6797\u7B49\u4EBA\u4E3A\u4E86\u5B9E\u73B0\u7535\u89C6\u673A\u3001\u7535\u8BDD\u3001\u95F9\u949F\u7B49\u5BB6\u7528\u7535\u5668\u7684\u63A7\u5236\u548C\u901A\u4FE1\uFF0C\u5F00\u53D1\u4E86\u4E00\u5957\u7528\u4E8E\u8BBE\u7F6E\u5728\u5BB6\u7528\u7535\u5668\u7B49\u5C0F\u578B\u7CFB\u7EDF\u4E2D\u7684\u7F16\u7A0B\u8BED\u8A00\u3002\u5728\u5F53\u65F6\uFF0C\u8FD9\u95E8\u8BED\u8A00\u88AB\u547D\u540D\u4E3A <code>Oka</code>\u3002\u4F46\u7531\u4E8E\u5E02\u573A\u9700\u6C42\u4E0D\u9AD8\uFF0C\u6240\u4EE5\u8BE5\u8BA1\u5212\u88AB\u9010\u6E10\u653E\u5F03\u3002</p><p>\u968F\u7740 1990 \u5E74\u4EE3\u4E92\u8054\u7F51\u7684\u53D1\u5C55\uFF0CSun \u516C\u53F8\u53D1\u73B0 <code>Oka</code> \u8BED\u8A00\u5728\u4E92\u8054\u7F51\u4E2D\u7684\u5E94\u7528\u524D\u666F\u5E7F\u6CDB\u3002\u4E8E\u662F\u51B3\u5B9A\u5BF9 <code>Oka</code> \u8FDB\u884C\u6539\u9020\uFF0C\u5E76\u5728 1995 \u5E74 5 \u6708\u4EE5 Java \u7684\u540D\u4E49\u6B63\u5F0F\u53D1\u5E03\u3002</p><p>\u968F\u7740\u4E92\u8054\u7F51\u7684\u8FC5\u731B\u53D1\u5C55\uFF0CJava \u4E5F\u5F97\u4EE5\u9010\u6E10\u6210\u4E3A\u91CD\u8981\u7684\u7F51\u7EDC\u7F16\u7A0B\u8BED\u8A00\uFF0C\u8A79\u59C6\u65AF\xB7\u9AD8\u65AF\u6797\u4E5F\u88AB\u5927\u5BB6\u516C\u8BA4\u4E3A Java \u4E4B\u7236\u3002</p><p>\u5230\u4E86 2009 \u5E74\uFF0C Sun \u516C\u53F8\u88AB Oracle \u516C\u53F8\u6240\u6536\u8D2D\uFF0C\u81EA\u6B64 Java \u6210\u4E3A Oracle \u516C\u53F8\u7684\u4E00\u5927\u4EA7\u54C1\u76F4\u81F3\u4ECA\u65E5\u3002</p><p>\u4EE5\u4E0B\u662F\u622A\u6B62\u5230\u672C\u6587\u5199\u4F5C\u65F6\u95F4\uFF082022 \u5E74 7 \u6708 23 \u65E5\uFF09Java \u7684\u5386\u53F2\u5E74\u8868\uFF0C\u7D2F\u8BA1\u7ECF\u8FC7\u4E86 18 \u6B21\u4E3B\u8981\u7248\u672C\u66F4\u65B0\uFF0C\u76EE\u524D\u6765\u5230\u4E86 Java SE 18\u3002\u800C Java SE 19 \u65E9\u671F\u9884\u89C8\u7248\u4E5F\u5DF2\u7ECF\u6D41\u51FA\uFF0C\u6839\u636E\u5B98\u65B9\u7ED9\u51FA\u7684\u53D1\u5E03\u65F6\u95F4\u8868\uFF0C\u5927\u6982\u4F1A\u5728 9 \u6708\u4EFD\u53D1\u5E03 Java SE 19 \u7684 GA \u7248\u672C\u3002\u4E0D\u8FC7\u867D\u7136 Java \u5DF2\u7ECF\u7ECF\u5386\u4E86\u8FD9\u4E48\u591A\u7248\u672C\u7684\u66F4\u65B0\uFF0C\u4F46\u56FD\u5185\u76EE\u524D\u7528\u7684\u6700\u591A\u7684\u5E94\u8BE5\u8FD8\u662F Java 1.8 \u7248\u672C\u3002\u800C\u5904\u4E8E\u5BF9\u7A33\u5B9A\u6027\u7684\u8003\u8651\uFF0C\u4F01\u4E1A\u5F00\u53D1\u66F4\u559C\u6B22 LTS \u7248\u672C\uFF0C\u8FD9\u4E5F\u662F\u4E3A\u4EC0\u4E48\u81F3\u4ECA Java 1.8 \u8FD8\u5360\u6709\u5982\u6B64\u9AD8\u7684\u5E02\u573A\u6BD4\u4F8B\u3002</p><table><thead><tr><th style="text-align:center;">\u7248\u672C</th><th style="text-align:center;">\u53D1\u5E03\u65E5\u671F</th><th style="text-align:center;">\u4E3B\u8981\u4E8B\u4EF6</th></tr></thead><tbody><tr><td style="text-align:center;">JDK Beta</td><td style="text-align:center;">1995</td><td style="text-align:center;">Java \u8BED\u8A00\u53D1\u5E03\uFF0C\u7528 Java \u5B9E\u73B0\u7684\u6D4F\u89C8\u5668\u548C Java Applet \u88AB\u5927\u91CF\u5E94\u7528</td></tr><tr><td style="text-align:center;">JDK 1.0</td><td style="text-align:center;">1996 \u5E74 1 \u6708</td><td style="text-align:center;">\u5960\u5B9A\u4E86JDK\u3001JRE\u3001JVM \u7684\u4F53\u7CFB\u7ED3\u6784</td></tr><tr><td style="text-align:center;">JDK 1.1</td><td style="text-align:center;">1997 \u5E74 2 \u6708</td><td style="text-align:center;">\u52A0\u5165 JIT\uFF0C\u63D0\u5347 JDK \u6548\u7387</td></tr><tr><td style="text-align:center;">J2SE 1.2</td><td style="text-align:center;">1998 \u5E74 12 \u6708</td><td style="text-align:center;">\u786E\u7ACB J2SE\u3001J2EE\u3001J2ME \u4EA7\u54C1\u7ED3\u6784</td></tr><tr><td style="text-align:center;">J2SE 1.3</td><td style="text-align:center;">2000 \u5E74 5 \u6708</td><td style="text-align:center;">\u5185\u7F6E HotSpot JVM</td></tr><tr><td style="text-align:center;">J2SE 1.4</td><td style="text-align:center;">2002 \u5E74 2 \u6708</td><td style="text-align:center;">XML \u5904\u7406\u3001\u65AD\u8A00\u3001\u652F\u6301\u6B63\u5219\u8868\u8FBE\u5F0F</td></tr><tr><td style="text-align:center;">J2SE 5.0</td><td style="text-align:center;">2004 \u5E74 9 \u6708</td><td style="text-align:center;">\u9759\u6001\u5BFC\u5165\u3001\u6CDB\u578B\u3001for-each \u5FAA\u73AF\u3001\u81EA\u52A8\u62C6\uFF0C\u88C5\u7BB1\u3001\u679A\u4E3E\u3001\u53EF\u53D8\u53C2\u6570</td></tr><tr><td style="text-align:center;">Java SE 6</td><td style="text-align:center;">2006 \u5E74 12 \u6708</td><td style="text-align:center;">\u63D0\u4F9B\u52A8\u6001\u8BED\u8A00\u652F\u6301\u3001\u540C\u6B65\u5783\u573E\u56DE\u6536</td></tr><tr><td style="text-align:center;">Java SE 7</td><td style="text-align:center;">2011 \u5E74 7 \u6708</td><td style="text-align:center;">\u5B57\u7B26\u4E32\u7684switch\u8BED\u53E5\u3001\u591A\u5F02\u5E38\u6355\u6293</td></tr><tr><td style="text-align:center;">Java SE 8 (LTS)</td><td style="text-align:center;">2014 \u5E74 3 \u6708</td><td style="text-align:center;">Lambda\u8868\u8FBE\u5F0F</td></tr><tr><td style="text-align:center;">Java SE 9</td><td style="text-align:center;">2017 \u5E74 9 \u6708</td><td style="text-align:center;">\u8F7B\u91CF\u7EA7 json API\u3001\u5783\u573E\u6536\u96C6\u673A\u5236\u66F4\u65B0</td></tr><tr><td style="text-align:center;">Java SE 10</td><td style="text-align:center;">2018 \u5E74 3 \u6708</td><td style="text-align:center;">\u5C40\u90E8\u53D8\u91CF\u7C7B\u578B\u63A8\u65AD\uFF0CJava \u540E\u7EED\u7248\u672C\u5FEB\u901F\u8FED\u4EE3\u66F4\u65B0</td></tr><tr><td style="text-align:center;">Java SE 11 (LTS)</td><td style="text-align:center;">2018 \u5E74 9 \u6708</td><td style="text-align:center;">\u5E38\u7528\u7C7B\u589E\u5F3A\uFF0CJava 11 \u662F\u7EE7 Java 8 \u4E4B\u540E\u7684\u9996\u4E2A\u957F\u671F\u652F\u6301\u672C\u7248</td></tr><tr><td style="text-align:center;">Java SE 12</td><td style="text-align:center;">2019 \u5E74 3 \u6708</td><td style="text-align:center;">switch \u8868\u8FBE\u5F0F\u589E\u5F3A</td></tr><tr><td style="text-align:center;">Java SE 13</td><td style="text-align:center;">2019 \u5E74 9 \u6708</td><td style="text-align:center;">\u6587\u672C\u5757\u652F\u6301</td></tr><tr><td style="text-align:center;">Java SE 14</td><td style="text-align:center;">2020 \u5E74 3 \u6708</td><td style="text-align:center;">instanceof \u652F\u6301\u6A21\u5F0F\u5339\u914D</td></tr><tr><td style="text-align:center;">Java SE 15</td><td style="text-align:center;">2020 \u5E74 9 \u6708</td><td style="text-align:center;">EdDSA \u6570\u5B57\u7B7E\u540D\u7B97\u6CD5\u3001 \u5BC6\u5C01\u7C7B\u3001\u9690\u85CF\u7C7B</td></tr><tr><td style="text-align:center;">Java SE 16</td><td style="text-align:center;">2021 \u5E74 3 \u6708</td><td style="text-align:center;">\u542F\u7528 C++ 14 \u8BED\u8A00\u7279\u6027\u3001Vector API</td></tr><tr><td style="text-align:center;"><strong>Java SE 17 (LTS)</strong></td><td style="text-align:center;">2021 \u5E74 9 \u6708</td><td style="text-align:center;">\u6062\u590D\u603B\u662F\u4E25\u683C\u7684\u6D6E\u70B9\u8BED\u4E49\u3001\u589E\u5F3A\u578B\u4F2A\u968F\u673A\u6570\u751F\u6210\u5668</td></tr><tr><td style="text-align:center;">Java SE 18</td><td style="text-align:center;">2022\u5E74 3\u6708</td><td style="text-align:center;">\u9ED8\u8BA4 UTF-8 \u7F16\u7801\u3001\u4EE3\u7801\u7247\u6BB5\u3001\u7B80\u5355\u7684\u7F51\u7EDC\u670D\u52A1\u5668</td></tr></tbody></table><h2 id="\u4E3A\u4EC0\u4E48\u4F7F\u7528-java" tabindex="-1"><a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u4F7F\u7528-java" aria-hidden="true">#</a> \u4E3A\u4EC0\u4E48\u4F7F\u7528 Java</h2><p>\u65E2\u7136\u7F16\u7A0B\u8BED\u8A00\u6709\u90A3\u4E48\u591A\uFF0C\u90A3\u6211\u4EEC\u4E3A\u4EC0\u4E48\u8981\u4F7F\u7528 Java \u8BED\u8A00\u5462\uFF1F\u4EE5\u4E0B\u5C31\u6765\u770B\u770B Java \u88AB\u5E7F\u6CDB\u4F7F\u7528\u7684\u51E0\u4E2A\u539F\u56E0\u3002</p><ol><li><strong>\u4E16\u754C\u8303\u56F4\u5185\u6D41\u884C\uFF0C\u56FD\u5185\u4F7F\u7528\u6700\u4E3A\u5E7F\u6CDB\u7684\u7F16\u7A0B\u8BED\u8A00\u4E4B\u4E00\u3002</strong></li></ol><p>\u4EE5\u4E0B\u662F\u622A\u6B62 2022 \u5E74 7 \u6708 TIOBE \u7EDF\u8BA1\u7684\u7F16\u7A0B\u8BED\u8A00\u6392\u884C\u699C\uFF0C\u53EF\u4EE5\u770B\u5230 Java \u5904\u4E8E\u524D\u4E09\u7684\u4F4D\u7F6E\u3002\u800C\u4ECE\u5386\u5E74\u7F16\u7A0B\u8BED\u8A00\u6240\u5360\u5E02\u573A\u4EFD\u989D\u8D8B\u52BF\u56FE\u4E5F\u53EF\u4EE5\u770B\u51FA\uFF0CJava \u867D\u7136\u6CA1\u6709\u4E00\u76F4\u72EC\u5360\u9CCC\u5934\uFF0C\u4F46\u7EDD\u5927\u6570\u65F6\u95F4\u90FD\u662F\u5360\u636E\u9886\u5148\u5730\u4F4D\u3002</p><p><img src="https://img-blog.csdnimg.cn/6637fb1c44b9454f98a730133d895747.png" alt="" loading="lazy"><img src="https://img-blog.csdnimg.cn/f9b7d09d943c4bb38f8ec076c504fe41.png" alt="" loading="lazy"></p><ol start="2"><li><strong>\u79FB\u690D\u6027\u9AD8</strong></li></ol><p>\u7531\u4E8E Java \u4E2D JVM \u7684\u7279\u6027\uFF0C\u6240\u4EE5\u80FD\u591F\u505A\u5230\u4E00\u6B21\u7F16\u8BD1\uFF0C\u968F\u5904\u8FD0\u884C\uFF0C\u5176\u79FB\u690D\u6027\u4E5F\u5C31\u66F4\u9AD8\u3002</p><ol start="3"><li><strong>\u5F00\u53D1\u793E\u533A\u5B8C\u5584</strong></li></ol><p>\u793E\u533A\u5B8C\u5584\u4E5F\u662F Java \u4E3A\u4EC0\u4E48\u4F7F\u7528\u591A\u7684\u539F\u56E0\uFF0C\u5404\u79CD\u5C01\u88C5 API\uFF0C\u6BD4\u8D77 C\u3001C++ \u8BED\u8A00\u4F7F\u7528\u8D77\u6765\u66F4\u52A0\u65B9\u4FBF\u3002\u867D\u7136 Python \u7684\u5C01\u88C5\u7A0B\u5EA6\u66F4\u9AD8\uFF0C\u4F46\u662F\u5176\u6548\u7387\u6BD4\u8D77 Java \u5374\u6253\u4E86\u6298\u6263\u3002\u6BD5\u7ADF\u5C01\u88C5\u7A0B\u5EA6\u548C\u6548\u7387\u662F\u6210\u53CD\u6BD4\u7684\uFF0CJava \u517C\u5177\u4E86\u6548\u7387\u9AD8\u548C\u4F7F\u7528\u65B9\u4FBF\u7684\u7279\u70B9\uFF0C\u6240\u4EE5\u66F4\u53D7\u4EBA\u4EEC\u9752\u7750\u3002</p><h2 id="java-\u80FD\u505A\u4EC0\u4E48" tabindex="-1"><a class="header-anchor" href="#java-\u80FD\u505A\u4EC0\u4E48" aria-hidden="true">#</a> Java \u80FD\u505A\u4EC0\u4E48</h2><p>Java \u5E94\u7528\u5E7F\u6CDB\uFF0C\u5728\u6211\u4EEC\u65E5\u5E38\u4E2D\u5C31\u80FD\u7ECF\u5E38\u89C1\u5230\u7531 Java \u6240\u5F00\u53D1\u7684\u7A0B\u5E8F\u3002\u5E38\u89C1\u7684\u7684\u5E94\u7528\u5E94\u7528\u9886\u57DF\u5982\u4E0B\uFF1A</p><ol><li><strong>\u684C\u9762 GUI \u5E94\u7528\u5F00\u53D1</strong></li><li><strong>\u670D\u52A1\u5668\u7CFB\u7EDF</strong></li><li><strong>\u4F01\u4E1A\u7EA7\u5E94\u7528\u5F00\u53D1</strong></li><li><strong>\u5927\u6570\u636E\u5F00\u53D1</strong></li><li><strong>\u79FB\u52A8\u5E94\u7528\u5F00\u53D1</strong></li><li><strong>\u6E38\u620F\u5F00\u53D1</strong></li><li>\u2026\u2026</li></ol><h2 id="java-\u6280\u672F\u4F53\u7CFB" tabindex="-1"><a class="header-anchor" href="#java-\u6280\u672F\u4F53\u7CFB" aria-hidden="true">#</a> Java \u6280\u672F\u4F53\u7CFB</h2><p>\u6839\u636E\u4F20\u7EDF\u610F\u4E49\u4E0A Sun \u5B98\u65B9\u5B9A\u4E49\uFF0C Java \u6280\u672F\u4F53\u7CFB\u7684\u7EC4\u6210\u4E3B\u8981\u5C31\u662F\u6211\u4EEC\u5E38\u8BF4\u7684 JDK\uFF0C\u5373\u4EE5\u4E0B\u4E09\u90E8\u5206\uFF1A</p><ol><li><strong>Java \u7A0B\u5E8F\u8BBE\u8BA1\u8BED\u8A00</strong></li><li><strong>Java \u865A\u62DF\u673A</strong></li><li><strong>Java API \u7C7B\u5E93</strong></li></ol><p><img src="https://img-blog.csdnimg.cn/4dfc7057ff0f406187a2c7def724b99a.png" alt="" loading="lazy"></p><p>\u540C\u65F6\uFF0CJava \u6280\u672F\u4F53\u7CFB\u53C8\u53EF\u4EE5\u4E3B\u8981\u5206\u4E3A\u4EE5\u4E0B 3 \u4E2A\u5E73\u53F0\u3002</p><ol><li><strong>Java SE</strong></li></ol><p>Java Standard Edition\uFF0C\u5373 Java \u6807\u51C6\u7248\u3002\u4E3B\u8981\u662F Java \u6280\u672F\u7684\u6838\u5FC3\u548C\u57FA\u7840\uFF0C\u8981\u60F3\u5B66\u597D Java\uFF0C\u90A3\u4E48\u9996\u5148\u4F60\u5F97\u638C\u63E1\u597D\u8FD9\u90E8\u5206\u3002\u4E3B\u8981\u8FD0\u884C\u5728\u684C\u9762\u7EA7\u5E94\u7528\uFF0C\u5982 Windows \u5E94\u7528\u7A0B\u5E8F\u3002</p><ol start="2"><li><strong>Java EE</strong></li></ol><p>Java Enterprise Editon\uFF0C\u5373 Java \u4F01\u4E1A\u7248\u3002\u4ECE\u5B83\u7684\u540D\u5B57\u5C31\u4E0D\u96BE\u770B\u51FA\uFF0C\u8FD9\u662F Java \u9488\u5BF9\u4F01\u4E1A\u7EA7\u5E94\u7528\u5F00\u53D1\u6240\u63D0\u4F9B\u7684\u4E00\u5957\u89E3\u51B3\u65B9\u6848\uFF0C\u4E3B\u8981\u7528\u4E8E\u67B6\u8BBE\u9AD8\u6027\u80FD\u4F01\u4E1A\u7F51\u7AD9\u3002</p><ol start="3"><li><strong>Java ME</strong></li></ol><p>Java Micro Edition\uFF0C\u5373 Java \u5C0F\u578B\u7248\u3002\u4E3B\u8981\u662F Java \u9488\u5BF9\u79FB\u52A8\u8BBE\u5907\u5E94\u7528\u6240\u63D0\u4F9B\u7684\u4E00\u5957\u89E3\u51B3\u65B9\u6848\uFF0C\u4E3B\u8981\u8FD0\u884C\u5728\u624B\u673A\u3001pad \u7B49\u79FB\u52A8\u7AEF\u3002</p><p><img src="https://img-blog.csdnimg.cn/b0ad3b942def40e2a6cec69f15072a27.png" alt="" loading="lazy"></p><h2 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h2><p>\u672C\u6587\u4E3B\u8981\u4ECE Java \u5386\u53F2\u80CC\u666F\u3001\u9009\u62E9 Java \u7684\u7406\u7531\u3001Java \u80FD\u505A\u4EC0\u4E48\u3001Java \u6280\u672F\u4F53\u7CFB\u7B49 4 \u65B9\u9762\u5BF9 Java \u8BED\u8A00\u505A\u4E86\u4E00\u4E2A\u7B80\u5355\u4ECB\u7ECD\u3002\u63A5\u4E0B\u6765\u7684\u6587\u7AE0\u6211\u4EEC\u5C31\u6765\u770B\u770B\uFF0C\u5982\u4F55\u642D\u5EFA Java \u7684\u5F00\u53D1\u73AF\u5883\u4EE5\u53CA\u5B9E\u73B0\u4E00\u4E2A\u7B80\u5355\u7684\u5165\u95E8\u7A0B\u5E8F\u3002</p>',35);function l(r,d){return n}var c=e(a,[["render",l],["__file","intro-to-java.html.vue"]]);export{c as default};
